SELECT c.customerid, c.companyname, o.orderid, o.orderdate, o.shippeddate, od.unitprice, od.quantity, od.discount, (od.unitprice * od.quantity * (1 - od.discount)) AS order_revenue FROM customers c JOIN orders o ON c.customerid = o.customerid JOIN "order details" od ON o.orderid = od.orderid WHERE (c.region = 'Western' OR c.region IS NULL) AND (strftime('%Y', o.shippeddate) = '1997')
